mapper.select:
SELECT COUNT(A.USER_ID) FROM t_user_info A WHERE A.USER_MEM_LVL = #{userMemLvl}
AND A.USER_NM LIKE CONCAT('%', #{srchWrd}, '%')
AND A.MOBILE LIKE CONCAT('%', #{srchWrd}, '%')
AND ( A.USER_NM LIKE CONCAT('%', #{srchWrd}, '%') )
AND A.POSITION1 = #{srchPosition1}

SELECT T.* FROM (
SELECT
A.*
FROM
t_user_info A
WHERE
A.USER_MEM_LVL = #{userMemLvl}



			AND A.USER_NM LIKE CONCAT('%', #{srchWrd}, '%')


			AND A.MOBILE LIKE CONCAT('%', #{srchWrd}, '%')


			AND (
			A.USER_NM LIKE CONCAT('%', #{srchWrd}, '%')
			)




	AND A.POSITION1 = #{srchPosition1}


ORDER BY RGSDE DESC
) AS T
LIMIT #{firstIndex}, #{row}

