UPDATE
t_user_info
SET
POST_NO = #{postNo}
,ADDR = #{addr}
,ADDR_DETAIL = #{addrDetail}
,ADDR_ETC = #{addrEtc} 

 ,tel= #{encTel} 
 ,mobile= #{encMobile} 
 ,email= #{encEmail} 
 ,user_org_cd= #{userOrgCd} 
 ,user_org_nm= #{userOrgNm} 
 ,user_grade_cd= #{userGradeCd} 
 ,user_grade_nm= #{userGradeNm} 
 ,sms_yn= #{smsYn} 
 ,USER_TP = #{userTp} 
 	,ETC = #{etc} 
 	,user_en_nm = #{userEnNm} 
 	,SUB_DN = #{subDn} 
WHERE
USER_ID = #{userId}

mapper.select:
SELECT COUNT(A.USER_ID) FROM t_user_info A, t_user_info_stdnt B WHERE A.USER_ID = B.USER_ID AND A.USER_MEM_LVL = #{userMemLvl}
AND DATE_FORMAT(A.LST_LOGIN_DE, '%Y%m%d') < #{compareDe}
AND A.LOGIN_ID LIKE CONCAT('%', #{srchWrd}, '%')
AND A.USER_NM LIKE CONCAT('%', #{srchWrd}, '%')
AND A.MOBILE LIKE CONCAT('%', #{srchWrd}, '%')
AND B.BELONG LIKE CONCAT('%', #{srchWrd}, '%')

SELECT T.* FROM ( SELECT A.*, B.USER_NM_EN, B.BELONG, B.POSITION, B.ADM_RGS_YN, B.SELF_AUTH_YN, B.TERMS_ACCEPT_DE FROM t_user_info A, t_user_info_stdnt B WHERE A.USER_ID = B.USER_ID AND A.USER_MEM_LVL = #{userMemLvl}
AND DATE_FORMAT(A.LST_LOGIN_DE, '%Y%m%d') < #{compareDe}
AND A.LOGIN_ID LIKE CONCAT('%', #{srchWrd}, '%')
AND A.USER_NM LIKE CONCAT('%', #{srchWrd}, '%')
AND A.MOBILE LIKE CONCAT('%', #{srchWrd}, '%')
AND B.BELONG LIKE CONCAT('%', #{srchWrd}, '%')
ORDER BY A.RGSDE DESC, A.USER_NM ASC ) AS T LIMIT #{firstIndex}, #{row}

SELECT A.*, B.USER_NM_EN, B.BELONG, B.POSITION, B.ADM_RGS_YN, B.SELF_AUTH_YN, B.TERMS_ACCEPT_DE FROM t_user_info A, t_user_info_stdnt B WHERE A.USER_ID = B.USER_ID AND A.USER_MEM_LVL = '9'
AND DATE_FORMAT(A.LST_LOGIN_DE, '%Y%m%d') < #{compareDe}
ORDER BY RGSDE DESC, USER_NM ASC LIMIT 0, #{row}

/**기관별 이메일 존재여부 체크 용도,엑셀일괄 등록*/
SELECT count(EMAIL) FROM t_user_info
WHERE EMAIL=#{encEmail}

/**기관별 이메일
존재여부 체크 용도,엑셀일괄 등록*/
SELECT count(LOGIN_ID) FROM t_user_info
WHERE LOGIN_ID=#{loginId}

/** 기관별
등록한 유저 마지막 아이디 */
SELECT
COALESCE(MAX(USER_ID),concat(#{orgCd},'_000000')) FROM t_user_info
WHERE USER_MEM_LVL=#{userMemLvl}
AND ORG_CD=#{orgCd}

/** 관리자에서 기관코드 등록 건수 */
SELECT COUNT(*) FROM t_org
WHERE ORG_CD=#{orgCd}

/** 관리자에서 기관이름 등록 건수 */
SELECT COUNT(*) FROM t_org
WHERE ORG_NM=#{orgNm} AND ORG_CD!=#{orgCd}

